// Plain serialisable data only (no functions) so it can be imported from
// either a Server or Client Component without breaking `next build`.

export type DocStatus = "確認済" | "未確認" | "要対応";

export interface TripLeg {
  id: string;
  /** 往路 / 復路 / 経由 */
  direction: "往路" | "復路";
  airline: "ANA" | "JAL";
  flightNo: string; // NH106 / JL62 etc.
  cabin: string; // エコノミー / プレミアムエコノミー / ビジネス
  date: string; // 2026/07/18 (出発日, 出発地の現地日付)
  from: {
    code: string; // HND
    city: string; // 東京/羽田
    terminal: string; // T3
    time: string; // 17:05
  };
  to: {
    code: string;
    city: string;
    terminal: string;
    time: string;
    /** 翌日着など */
    dayOffset?: number;
  };
  durationLabel: string; // 所要 9時間55分
  seat: string; // 42K
  gate: string; // 142
  boardingTime: string; // 16:25
  /** 出発地と到着地の時差表記 */
  timeDiffNote: string;
}

export interface DocItem {
  id: string;
  label: string;
  description: string;
  status: DocStatus;
  /** 初期チェック状態（確認済なら true） */
  checked: boolean;
}

export interface EntryRequirement {
  label: string;
  value: string;
  note?: string;
}

