"use client";

// 渡航書類チェックリスト — wraps gunjo's CheckList (checkbox + label +
// description + trailing slot). CheckList owns the checkbox a11y wiring; we own
// the controlled state, the status→Badge mapping, and the progress summary.
//
// "use client" is required: CheckList takes a function prop (onCheckedChange)
// and we hold useState here.

import * as React from "react";
import { IconCircleCheck, IconAlertTriangle, IconCircleDot } from "@tabler/icons-react";
import { CheckList, Badge, Progress } from "@gunjo/ui";
import type { CheckListItem } from "@gunjo/ui";

import { DOC_ITEMS, type DocItem, type DocStatus } from "./data";

function StatusBadge({ status }: { status: DocStatus }) {
  if (status === "確認済") {
    return (
      <Badge variant="success" icon={<IconCircleCheck />}>
        確認済
      </Badge>
    );
  }
  if (status === "要対応") {
    return (
      <Badge variant="destructive" icon={<IconAlertTriangle />}>
        要対応
      </Badge>
    );
  }
  return (
    <Badge variant="warning" icon={<IconCircleDot />}>
      未確認
    </Badge>
  );
}

export function DocumentChecklist() {
  const [checked, setChecked] = React.useState<Record<string, boolean>>(() =>
    Object.fromEntries(DOC_ITEMS.map((d) => [d.id, d.checked]))
  );

  const handleChange = React.useCallback((id: string, value: boolean) => {
    setChecked((prev) => ({ ...prev, [id]: value }));
  }, []);

  const doneCount = DOC_ITEMS.filter((d) => checked[d.id]).length;
  const total = DOC_ITEMS.length;
  const allDone = doneCount === total;

  // status reflects the live checkbox: a ticked row counts as 確認済,
  // an unticked "要対応" stays 要対応, everything else unticked is 未確認.
  const itemStatus = (d: DocItem): DocStatus => {
    if (checked[d.id]) return "確認済";
    return d.status === "要対応" ? "要対応" : "未確認";
  };

  const items: CheckListItem[] = DOC_ITEMS.map((d) => ({
    id: d.id,
    label: d.label,
    description: d.description,
    checked: checked[d.id],
    trailing: <StatusBadge status={itemStatus(d)} />,
  }));

  return (
    <div className="flex flex-col gap-3">
      <div className="flex items-center justify-between gap-3">
        <p
          className="text-sm font-medium text-foreground"
          aria-live="polite"
        >
          {doneCount} / {total} 項目を確認済
        </p>
        {allDone ? (
          <Badge variant="success" icon={<IconCircleCheck />}>
            渡航準備OK
          </Badge>
        ) : (
          <Badge variant="warning">未完了あり</Badge>
        )}
      </div>

      <Progress
        value={(doneCount / total) * 100}
        tone={allDone ? "success" : "warning"}
        label="渡航書類チェックの進捗"
        valueText={`確認済 ${doneCount}/${total}`}
      />

      <CheckList items={items} onCheckedChange={handleChange} />

      <p className="text-xs text-muted-foreground">
        チェックは端末内の控え表示用です。実際の入国可否は渡航先・航空会社の最新案内をご確認ください。
      </p>
    </div>
  );
}

// Hand-rolled boarding-pass / eチケット券面 (ticket stub).
//
// @gunjo/ui has NO ticket-stub / boarding-pass / pass-card primitive, so the
// visual ticket (OD pair + times + seat/gate + QR/barcode + perforation notch)
// is hand-rolled. We still compose gunjo primitives where they fit (Badge for
// the cabin/status pills, Separator for the perforation rule, Icon for the
// glyphs) and lean on gunjo design tokens (bg-card, border-border, text-*).
//
// Presentational only — no function props — so this stays RSC-safe and can be
// rendered inside a Server Component if needed.

import * as React from "react";
import {
  IconPlane,
  IconArrowRight,
  IconArmchair,
  IconDoor,
  IconClockHour8,
  IconQrcode,
} from "@tabler/icons-react";
import { Badge, Separator, Icon } from "@gunjo/ui";

import type { TripLeg } from "./data";

interface TicketStubProps {
  leg: TripLeg;
  pnr: string;
  passengerName: string;
}

function AirportEnd({
  code,
  city,
  time,
  align,
}: {
  code: string;
  city: string;
  time: string;
  align: "start" | "end";
}) {
  return (
    <div className={align === "end" ? "text-right" : "text-left"}>
      <p className="text-3xl font-bold leading-none tracking-tight text-foreground tabular-nums">
        {code}
      </p>
      <p className="mt-1 truncate text-xs text-muted-foreground">{city}</p>
      <p className="mt-1 text-lg font-semibold leading-none tabular-nums text-foreground">
        {time}
      </p>
    </div>
  );
}

/** A field cell for the seat/gate/boarding strip. */
function StubField({
  icon,
  label,
  value,
}: {
  icon: React.ReactNode;
  label: string;
  value: string;
}) {
  return (
    <div className="flex min-w-0 flex-col gap-0.5">
      <span className="flex items-center gap-1 text-[10px] font-medium uppercase tracking-wide text-muted-foreground">
        {icon}
        {label}
      </span>
      <span className="truncate text-sm font-semibold text-foreground tabular-nums">
        {value}
      </span>
    </div>
  );
}

export function TicketStub({ leg, pnr, passengerName }: TicketStubProps) {
  return (
    <section
      aria-label={`搭乗券 ${leg.airline} ${leg.flightNo} ${leg.from.code} から ${leg.to.code}`}
      className="overflow-hidden rounded-2xl border border-border bg-card text-card-foreground shadow-sm"
    >
      {/* Header band — airline / flight / direction */}
      <div className="flex items-center justify-between gap-2 bg-foreground px-4 py-3 text-background">
        <div className="flex items-center gap-2">
          <Icon icon={IconPlane} size="md" decorative className="text-background" />
          <span className="text-sm font-semibold tracking-wide">
            {leg.airline} ・ {leg.flightNo}
          </span>
        </div>
        <span className="rounded-full bg-background/15 px-2.5 py-0.5 text-xs font-medium">
          {leg.direction}
        </span>
      </div>

      {/* OD pair */}
      <div className="px-4 pt-4">
        <p className="text-xs text-muted-foreground">{leg.date}</p>
        <div className="mt-2 flex items-end justify-between gap-3">
          <AirportEnd
            code={leg.from.code}
            city={leg.from.city}
            time={leg.from.time}
            align="start"
          />
          <div className="flex flex-1 flex-col items-center gap-1 pb-1">
            <Icon
              icon={IconArrowRight}
              size="sm"
              decorative
              className="text-muted-foreground"
            />
            <span className="whitespace-nowrap text-[10px] text-muted-foreground">
              {leg.durationLabel}
            </span>
          </div>
          <AirportEnd
            code={leg.to.code}
            city={leg.to.city}
            time={
              leg.to.dayOffset
                ? `${leg.to.time} +${leg.to.dayOffset}`
                : leg.to.time
            }
            align="end"
          />
        </div>
        <p className="mt-2 text-[11px] text-muted-foreground">
          {leg.from.terminal} → {leg.to.terminal} ・ {leg.timeDiffNote}
        </p>
      </div>

      {/* Seat / gate / boarding / cabin strip */}
      <div className="mt-4 grid grid-cols-3 gap-3 px-4">
        <StubField
          icon={<IconArmchair className="h-3 w-3" aria-hidden />}
          label="座席"
          value={leg.seat}
        />
        <StubField
          icon={<IconDoor className="h-3 w-3" aria-hidden />}
          label="搭乗口"
          value={leg.gate}
        />
        <StubField
          icon={<IconClockHour8 className="h-3 w-3" aria-hidden />}
          label="搭乗時刻"
          value={leg.boardingTime}
        />
      </div>
      <div className="mt-3 px-4">
        <Badge variant="info">{leg.cabin}</Badge>
      </div>

      {/* Perforation: notch + dashed rule */}
      <div className="relative mt-4">
        <span
          aria-hidden
          className="absolute -left-2 top-1/2 h-4 w-4 -translate-y-1/2 rounded-full border border-border bg-background"
        />
        <span
          aria-hidden
          className="absolute -right-2 top-1/2 h-4 w-4 -translate-y-1/2 rounded-full border border-border bg-background"
        />
        <div className="px-4">
          <Separator className="border-0 border-t border-dashed border-border bg-transparent" />
        </div>
      </div>

      {/* Stub footer — passenger + PNR + QR/barcode placeholder */}
      <div className="flex items-center justify-between gap-3 px-4 py-4">
        <div className="min-w-0">
          <p className="text-[10px] font-medium uppercase tracking-wide text-muted-foreground">
            搭乗者
          </p>
          <p className="truncate text-sm font-semibold text-foreground">
            {passengerName}
          </p>
          <p className="mt-1 text-[10px] font-medium uppercase tracking-wide text-muted-foreground">
            予約番号 (PNR)
          </p>
          <p className="font-mono text-sm font-bold tracking-[0.2em] text-foreground">
            {pnr}
          </p>
        </div>
        {/* QR placeholder — real app would render an encoded 2-D code */}
        <div
          role="img"
          aria-label={`搭乗用QRコード（予約番号 ${pnr}）`}
          className="flex h-20 w-20 shrink-0 items-center justify-center rounded-lg border border-border bg-muted"
        >
          <IconQrcode className="h-14 w-14 text-foreground" aria-hidden />
        </div>
      </div>

      {/* Barcode placeholder strip — uses the gunjo --foreground HSL channels
          (theme exposes `hsl(var(--foreground))`, not a --color-* variable). */}
      <div
        aria-hidden
        className="mx-4 mb-4 h-9 rounded"
        style={{
          backgroundImage:
            "repeating-linear-gradient(90deg, hsl(var(--foreground)) 0, hsl(var(--foreground)) 2px, transparent 2px, transparent 5px)",
        }}
      />
    </section>
  );
}
